queries.sql:
SELECT DISTINCT t.fullname, ts.Name
FROM Teacher t
JOIN Academic_Discipline ts ON t.DisciplineID = ts.DisciplineID;

SELECT DISTINCT t.fullname, ts.Name
FROM Teacher t
JOIN Grade_Level ts ON t.GradeLevelID = ts.LevelID;

SELECT DISTINCT t.fullname, gl.Name, ts.Name
FROM Teacher t
JOIN Academic_Discipline ts ON t.DisciplineID = ts.DisciplineID  JOIN Grade_Level gl ON t.GradeLevelID = gl.LevelID;

SELECT s.fullname, ts.Name
FROM Academic_Discipline ts
JOIN Student s ON ts.DisciplineID = s.DisciplineID;

SELECT s.fullname, ts.Name
FROM Grade_Level ts
JOIN Student s ON s.GradeLevelID = ts.LevelID;

SELECT s.fullname, gl.Name, ts.Name
FROM Academic_Discipline ts
JOIN Student s ON ts.DisciplineID = s.DisciplineID JOIN Grade_Level gl ON s.GradeLevelID = gl.LevelID;

