PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT DISTINCT ?fullname ?name WHERE {
  ?t a :Teachers .
  ?ts a :Academic_Discipline .
  ?t p:hasAcademic_Discipline ?ts .
  ?t p:name ?fullname .
  ?ts p:name ?name .
} }
  full: { SELECT DISTINCT ?fullname ?name ?name2 WHERE {
  ?t a :Teachers .
  ?ts a :Academic_Discipline .
  ?t p:hasAcademic_Discipline ?ts .
  ?gl a :Grade_Level .
  ?t p:hasGrade_Level ?gl .
  ?t p:name ?fullname .
  ?gl p:name ?name .
  ?ts p:name ?name2 .
} }
  component_2: { SELECT DISTINCT ?fullname ?name WHERE {
  ?t a :Teachers .
  ?ts a :Grade_Level .
  ?t p:hasGrade_Level ?ts .
  ?t p:name ?fullname .
  ?ts p:name ?name .
} }
}

